const VALID_RELATIONSHIP_TYPES: ReadonlySet<CityRelationshipType> = new Set([
  "nearby_city", "same_region", "same_corridor", "weekend_trip",
  "coastal_cluster", "mountain_cluster", "lake_cluster", "cross_border",
]);
const MAX_RELATED = 10;

function assertDiscoveryGraph(graph: Record<string, readonly RelatedCity[]>): void {
  const citySlugs = new Set(cities.map((c) => c.slug));
  const errors: string[] = [];
  for (const [slug, related] of Object.entries(graph)) {
    if (!citySlugs.has(slug)) errors.push(`${slug}: source city not found in cities.ts`);
    if (related.length > MAX_RELATED) errors.push(`${slug}: ${related.length} related cities exceeds max ${MAX_RELATED}`);
    const seen = new Set<string>();
    for (const r of related) {
      if (r.citySlug === slug) errors.push(`${slug}: self-reference`);
      if (seen.has(r.citySlug)) errors.push(`${slug}: duplicate reference to ${r.citySlug}`);
      seen.add(r.citySlug);
      if (!citySlugs.has(r.citySlug)) errors.push(`${slug}: related city ${r.citySlug} not found in cities.ts`);
      if (!VALID_RELATIONSHIP_TYPES.has(r.relationshipType)) errors.push(`${slug}: invalid relationshipType ${r.relationshipType}`);
      if (typeof r.distanceKm !== "number" || r.distanceKm <= 0) errors.push(`${slug}: non-positive distanceKm for ${r.citySlug}`);
    }
  }
  if (errors.length > 0) {
    throw new Error(`Invalid city discovery graph (${errors.length}):\n  - ${errors.join("\n  - ")}`);
  }
}

// Build-time gate: fails `next build` on any invalid edge.
assertDiscoveryGraph(CITY_DISCOVERY_GRAPH);

export function getRelatedCities(citySlug: string): readonly RelatedCity[] {
  return CITY_DISCOVERY_GRAPH[citySlug] ?? [];
}

export function hasRelatedCities(citySlug: string): boolean {
  return getRelatedCities(citySlug).length > 0;
}

const RELATIONSHIP_LABEL: Record<CityRelationshipType, string> = {
  nearby_city: "Nearby city",
  same_region: "Same region",
  same_corridor: "Same corridor",
  weekend_trip: "Weekend trip",
  coastal_cluster: "Coastal cluster",
  mountain_cluster: "Mountain cluster",
  lake_cluster: "Lake cluster",
  cross_border: "Cross-border",
};
export function getCityRelationshipLabel(t: CityRelationshipType): string {
  return RELATIONSHIP_LABEL[t];
}
